mapper.sql:
be.is_deleted = 0

    and be.tenant_id = #{tenantId}


    and exists (
        select 1
        from biz_user_enterprise current_rel
        where current_rel.enterprise_id = be.enterprise_id
          and current_rel.user_id = #{accessibleUserId}
          and current_rel.status = 1
          and current_rel.is_deleted = 0
    )

mapper.select:
select
from biz_enterprise be left join blade_user bu on bu.id = be.admin_user_id and bu.is_deleted = 0 where
and ( be.enterprise_name like concat('%', #{enterprise.keyword}, '%') or bu.real_name like concat('%', #{enterprise.keyword}, '%') or bu.account like concat('%', #{enterprise.keyword}, '%') )
and be.enterprise_type = #{enterprise.enterpriseType}
and be.status = #{enterprise.status}
order by be.enterprise_id desc
